const (
	ghAwHookScriptName = "ghr-gh-aw-job-started.sh"
	// GhAwJobStartedEnvKey is the actions/runner job hook variable (ADR 1751).
	GhAwJobStartedEnvKey = "ACTIONS_RUNNER_HOOK_JOB_STARTED"
)

// GhAwJobStartedHookShell removes /tmp/gh-aw before each job so gh-aw-actions/setup can recreate it.
// Prefers docker (root in container) when available; falls back to sudo -n. Always exits 0.
func GhAwJobStartedHookShell() string {
	return `#!/bin/sh
set -eu
if command -v docker >/dev/null 2>&1; then
	docker run --rm --network none -v /tmp:/host_tmp:rw alpine:3.20 sh -c 'rm -rf /host_tmp/gh-aw' 2>/dev/null || true
fi
sudo -n rm -rf /tmp/gh-aw 2>/dev/null || true
exit 0
`
}

// MergeRunnerDotenvLine sets or replaces a KEY=value line in dotenv-style content (one var per line).
// Other lines and blank lines are preserved. key must be non-empty and must not contain '='.
func MergeRunnerDotenvLine(content, key, value string) string {
	if key == "" || strings.Contains(key, "=") {
		return content
	}
	line := key + "=" + value
	var b strings.Builder
	seen := false
	lines := strings.Split(content, "\n")
	// Preserve trailing newline behavior: if content ended with \n, last element may be ""
	for i, ln := range lines {
		if i > 0 {
			b.WriteByte('\n')
		}
		if ln == "" {
			continue
		}
		idx := strings.IndexByte(ln, '=')
		if idx > 0 && ln[:idx] == key {
			if !seen {
				b.WriteString(line)
				seen = true
			}
			continue
		}
		b.WriteString(ln)
	}
	if !seen {
		if b.Len() > 0 && !strings.HasSuffix(content, "\n") && content != "" {
			b.WriteByte('\n')
		}
		if b.Len() > 0 {
			b.WriteByte('\n')
		}
		b.WriteString(line)
	}
	out := b.String()
	if content != "" && !strings.HasSuffix(out, "\n") {
		out += "\n"
	}
	if content == "" {
		return line + "\n"
	}
	return out
}

// RemoveRunnerDotenvKey drops all lines starting with key= from dotenv content.
func RemoveRunnerDotenvKey(content, key string) string {
	if key == "" {
		return content
	}
	prefix := key + "="
	var b strings.Builder
	first := true
	for _, ln := range strings.Split(content, "\n") {
		if ln != "" && strings.HasPrefix(ln, prefix) {
			continue
		}
		if !first {
			b.WriteByte('\n')
		}
		first = false
		b.WriteString(ln)
	}
	out := b.String()
	if strings.HasSuffix(content, "\n") && out != "" && !strings.HasSuffix(out, "\n") {
		out += "\n"
	}
	if content == "" {
		return ""
	}
	return out
}

// SyncNativeGhAwTmpHook writes or removes the gh-aw /tmp cleanup hook for a Linux native runner directory.
func SyncNativeGhAwTmpHook(h *host.Host, rc *config.RunnerConfig, instanceName string) error {
	if h.OS != "linux" || rc.EffectiveMode(h.OS) != "native" {
		return nil
	}
	absDir, err := autostart.AbsRunnerDir(h, instanceName)
	if err != nil {
		return err
	}
	scriptPath := path.Join(absDir, ghAwHookScriptName)
	envPath := path.Join(absDir, ".env")

	if !rc.NativeCleanGhAwTmp {
		if _, err := h.Run("rm -f " + autostart.PosixSingleQuote(scriptPath)); err != nil {
			return fmt.Errorf("removing gh-aw hook script: %w", err)
		}
		out, err := h.Run("cat " + autostart.PosixSingleQuote(envPath) + " 2>/dev/null || true")
		if err != nil {
			return fmt.Errorf("reading .env: %w", err)
		}
		updated := RemoveRunnerDotenvKey(out, GhAwJobStartedEnvKey)
		if err := autostart.WriteRemoteBytesForRunner(h, envPath, []byte(updated)); err != nil {
			return fmt.Errorf("writing .env: %w", err)
		}
		return nil
	}

	if err := autostart.WriteRemoteBytesForRunner(h, scriptPath, []byte(GhAwJobStartedHookShell())); err != nil {
		return fmt.Errorf("writing gh-aw hook script: %w", err)
	}
	if _, err := h.Run("chmod +x " + autostart.PosixSingleQuote(scriptPath)); err != nil {
		return fmt.Errorf("chmod hook script: %w", err)
	}

	out, err := h.Run("cat " + autostart.PosixSingleQuote(envPath) + " 2>/dev/null || true")
	if err != nil {
		return fmt.Errorf("reading .env: %w", err)
	}
	merged := MergeRunnerDotenvLine(strings.TrimSuffix(out, "\n"), GhAwJobStartedEnvKey, scriptPath)
	if !strings.HasSuffix(merged, "\n") {
		merged += "\n"
	}
	if err := autostart.WriteRemoteBytesForRunner(h, envPath, []byte(merged)); err != nil {
		return fmt.Errorf("writing .env: %w", err)
	}
	return nil
}

