package runner

import (
	"strings"
	"testing"
)

func TestMergeRunnerDotenvLine(t *testing.T) {
	t.Parallel()
	key := GhAwJobStartedEnvKey
	val := "/home/u/.ghr/runners/ci-1/ghr-gh-aw-job-started.sh"

	got := MergeRunnerDotenvLine("", key, val)
	want := key + "=" + val + "\n"
	if got != want {
		t.Fatalf("empty content: got %q want %q", got, want)
	}

	base := "FOO=bar\nBAZ=qux\n"
	got2 := MergeRunnerDotenvLine(base, key, val)
	if !strings.Contains(got2, "FOO=bar") || !strings.Contains(got2, "BAZ=qux") {
		t.Fatalf("should preserve other keys: %q", got2)
	}
	if !strings.Contains(got2, want) {
		t.Fatalf("should append hook: %q", got2)
	}

	prev := base + key + "=/old/path\n"
	got3 := MergeRunnerDotenvLine(prev, key, val)
	if strings.Contains(got3, "/old/path") {
		t.Fatalf("should replace old hook line: %q", got3)
	}
	if !strings.Contains(got3, val) {
		t.Fatalf("should contain new path: %q", got3)
	}
}

func TestRemoveRunnerDotenvKey(t *testing.T) {
	t.Parallel()
	key := GhAwJobStartedEnvKey
	in := "A=1\n" + key + "=/x\nB=2\n"
	got := RemoveRunnerDotenvKey(in, key)
	if strings.Contains(got, "HOOK") || strings.Contains(got, "/x") {
		t.Fatalf("should remove hook line: %q", got)
	}
	if !strings.Contains(got, "A=1") || !strings.Contains(got, "B=2") {
		t.Fatalf("should keep others: %q", got)
	}
	if got != "A=1\nB=2\n" {
		t.Fatalf("unexpected output: %q", got)
	}
}

func TestGhAwJobStartedHookShell(t *testing.T) {
	t.Parallel()
	s := GhAwJobStartedHookShell()
	if !strings.Contains(s, "docker run") || !strings.Contains(s, "alpine:3.20") {
		t.Fatalf("expected docker alpine cleanup: %s", s)
	}
	if !strings.Contains(s, "sudo -n rm -rf /tmp/gh-aw") {
		t.Fatalf("expected sudo fallback: %s", s)
	}
	if !strings.HasPrefix(strings.TrimSpace(s), "#!/bin/sh") {
		t.Fatalf("expected shebang: %s", s)
	}
}

